import React from 'react';
import { graphql } from 'gatsby';
import Layout from '../components/layout';
import SEO from '../components/seo';
import Image from 'gatsby-image';

const BeerCollection = ({ data, location }) => {
  const siteTitle = data.site.siteMetadata?.title || `Title`;
  console.log(data.file)

  return (
    <Layout location={location} title={siteTitle}>
      <SEO preview={data.file.childImageSharp.fluid} title="Beer Can Collection" />

      <h1>Beer Can Collection</h1>
      <p>My collection of beer cans, including some other different products.</p>

      <div className="collection-main">
        <Image
          fluid={data.file.childImageSharp.fluid}
          fadeIn={true}
        />
      </div>

      <div className="beer-container">
        {data.allFile.edges.map((image, index) => {
          const title = image.node.base.split('.')[0];

          return (
            <div>
              <Image
                fluid={image.node.childImageSharp.fluid}
                alt={title}
                key={index}
                title={title}
                fadeIn={true}
              />
              <span key={index + 10}>{title}</span>
            </div>
          )
        })}
      </div>
    </Layout>
  )
}

export default BeerCollection;

export const pageQuery = graphql`
  query {
    allFile (
      filter: {
        extension: { regex: "/(jpg)|(png)|(jpeg)/" }
        relativeDirectory: { eq: "beer" }
      }
    ) {
      edges {
        node {
          base
          childImageSharp {
            fluid {
              base64
              aspectRatio
              src
              srcSet
              sizes
            }
          }
        }
      }
    }

    site {
      siteMetadata {
        title
      }
    }

    file(relativePath: { eq: "collection.jpg" }) {
      childImageSharp {
        fluid {
          ...GatsbyImageSharpFluid
        }
      }
    }

    allMarkdownRemark(sort: { fields: [frontmatter___date], order: DESC }) {
      nodes {
        excerpt
        fields {
          slug
        }
        frontmatter {
          date(formatString: "MMMM DD, YYYY")
          title
          description
          isTranslation
        }
      }
    }
  }
`;
